/**
 * Process the frame if it is the last frame
 * @param webSocketImpl the websocket impl
 * @param frame the frame
 * @throws InvalidDataException if there is a protocol error
 */
private void processFrameIsFin(WebSocketImpl webSocketImpl, Framedata frame) throws InvalidDataException {
	if( currentContinuousFrame == null ) {
		log.trace( "Protocol error: Previous continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
	}
	addToBufferList(frame.getPayloadData());
	checkBufferLimit();
	if( currentContinuousFrame.getOpcode() == Opcode.TEXT ) {
		((FramedataImpl1) currentContinuousFrame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) currentContinuousFrame).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( currentContinuousFrame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			logRuntimeException(webSocketImpl, e);
		}
	} else if( currentContinuousFrame.getOpcode() == Opcode.BINARY ) {
		((FramedataImpl1) currentContinuousFrame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) currentContinuousFrame).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, currentContinuousFrame.getPayloadData() );
		} catch ( RuntimeException e ) {
			logRuntimeException(webSocketImpl, e);
		}
	}
	currentContinuousFrame = null;
	clearBufferList();
}

public void run() {
	if( thread != null )
		throw new IllegalStateException( "This instance of " + getClass().getSimpleName() + " can only be started once the same time." );
	thread = Thread.currentThread();
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		server.socket().bind( address );
		//InetAddress.getLocalHost()
		selector = Selector.open();
		server.register( selector, server.validOps() );
	} catch ( IOException ex ) {
		onWebsocketError( null, ex );
		return;
	}

	while ( !thread.isInterrupted() ) {
		SelectionKey key = null;
		WebSocket conn = null;
		try {
			selector.select();
			Set<SelectionKey> keys = selector.selectedKeys();
			Iterator<SelectionKey> i = keys.iterator();

			while ( i.hasNext() ) {
				key = i.next();

				// Remove the current key
				i.remove();

				// if isAcceptable == true
				// then a client required a connection
				if( key.isAcceptable() ) {
					SocketChannel client = server.accept();
					client.configureBlocking( false );
					WebSocket c = new WebSocket( this, Collections.singletonList( draft ), client.socket().getChannel() );
					client.register( selector, SelectionKey.OP_READ, c );
				}

				// if isReadable == true
				// then the server is ready to read
				if( key.isReadable() ) {
					conn = (WebSocket) key.attachment();
					conn.handleRead();
				}

				// if isWritable == true
				// then we need to send the rest of the data to the client
				if( key.isValid() && key.isWritable() ) {
					conn = (WebSocket) key.attachment();
					conn.flush();
					key.channel().register( selector, SelectionKey.OP_READ, conn );
				}
			}
			Iterator<WebSocket> it = this.connections.iterator();
			while ( it.hasNext() ) {
				// We have to do this check here, and not in the thread that
				// adds the buffered data to the WebSocket, because the
				// Selector is not thread-safe, and can only be accessed
				// by this thread.
				conn = it.next();
				if( conn.hasBufferedData() ) {
					conn.flush();
					// key.channel().register( selector, SelectionKey.OP_READ | SelectionKey.OP_WRITE, conn );
				}
			}
		} catch ( IOException ex ) {
			if( key != null )
				key.cancel();
			onWebsocketError( conn, ex );// conn may be null here
			if( conn != null ) {
				conn.close( CloseFrame.ABNROMAL_CLOSE );
			}
		}
	}
}

public void run() {
	synchronized ( this ) {
		if( selectorthread != null )
			throw new IllegalStateException( getClass().getName() + " can only be started once." );
		selectorthread = Thread.currentThread();
		if( isclosed.get() ) {
			return;
		}
	}
	selectorthread.setName( "WebSocketSelector-" + selectorthread.getId() );
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		ServerSocket socket = server.socket();
		socket.setReceiveBufferSize( WebSocketImpl.RCVBUF );
		socket.setReuseAddress( isReuseAddr() );
		socket.bind( address );
		selector = Selector.open();
		server.register( selector, server.validOps() );
		startConnectionLostTimer();
		onStart();
	} catch ( IOException ex ) {
		handleFatal( null, ex );
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						// Object o = key.attachment();
						continue;
					}

					if( key.isAcceptable() ) {
						if( !onConnect( key ) ) {
							key.cancel();
							continue;
						}

						SocketChannel channel = server.accept();
						if(channel==null){
							continue;
						}
						channel.configureBlocking( false );
						Socket socket = channel.socket();
						socket.setTcpNoDelay( isTcpNoDelay() );
						socket.setKeepAlive( true );
						WebSocketImpl w = wsf.createWebSocket( this, drafts );
						w.setSelectionKey(channel.register( selector, SelectionKey.OP_READ, w ));
						try {
							w.channel = wsf.wrapChannel( channel, w.getSelectionKey() );
							i.remove();
							allocateBuffers( w );
							continue;
						} catch (IOException ex) {
							if( w.getSelectionKey() != null )
								w.getSelectionKey().cancel();

							handleIOException( w.getSelectionKey(), null, ex );
						}
						continue;
					}

					if( key.isReadable() ) {
						conn = (WebSocketImpl) key.attachment();
						ByteBuffer buf = takeBuffer();
						if(conn.channel == null){
							if( key != null )
								key.cancel();

							handleIOException( key, conn, new IOException() );
							continue;
						}
						try {
							if( SocketChannelIOHelper.read( buf, conn, conn.channel ) ) {
								if( buf.hasRemaining() ) {
									conn.inQueue.put( buf );
									queue( conn );
									i.remove();
									if( conn.channel instanceof WrappedByteChannel ) {
										if( ( (WrappedByteChannel) conn.channel ).isNeedRead() ) {
											iqueue.add( conn );
										}
									}
								} else
									pushBuffer( buf );
							} else {
								pushBuffer( buf );
							}
						} catch ( IOException e ) {
							pushBuffer( buf );
							throw e;
						}
					}
					if( key.isWritable() ) {
						conn = (WebSocketImpl) key.attachment();
						if( SocketChannelIOHelper.batch( conn, conn.channel ) ) {
							if( key.isValid() )
								key.interestOps( SelectionKey.OP_READ );
						}
					}
				}
				while ( !iqueue.isEmpty() ) {
					conn = iqueue.remove( 0 );
					WrappedByteChannel c = ( (WrappedByteChannel) conn.channel );
					ByteBuffer buf = takeBuffer();
					try {
						if( SocketChannelIOHelper.readMore( buf, conn, c ) )
							iqueue.add( conn );
						if( buf.hasRemaining() ) {
							conn.inQueue.put( buf );
							queue( conn );
						} else {
							pushBuffer( buf );
						}
					} catch ( IOException e ) {
						pushBuffer( buf );
						throw e;
					}

				}
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				return;// FIXME controlled shutdown (e.g. take care of buffermanagement)
			}
		}

	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		stopConnectionLostTimer();
		if( decoders != null ) {
			for( WebSocketWorker w : decoders ) {
				w.interrupt();
			}
		}
		if( selector != null ) {
			try {
				selector.close();
			} catch ( IOException e ) {
				log.error( "IOException during selector.close", e );
				onError( null, e );
			}
		}
		if( server != null ) {
			try {
				server.close();
			} catch ( IOException e ) {
				log.error( "IOException during server.close", e );
				onError( null, e );
			}
		}
	}
}

@Override
public HandshakeState acceptHandshakeAsClient( ClientHandshake request, ServerHandshake response ) throws InvalidHandshakeException {
	if (! basicAccept( response )) {
		log.trace("acceptHandshakeAsClient - Missing/wrong upgrade or connection in handshake.");
		return HandshakeState.NOT_MATCHED;
	}
	if( !request.hasFieldValue( SEC_WEB_SOCKET_KEY ) || !response.hasFieldValue( SEC_WEB_SOCKET_ACCEPT ) ) {
		log.trace("acceptHandshakeAsClient - Missing Sec-WebSocket-Key or Sec-WebSocket-Accept");
		return HandshakeState.NOT_MATCHED;
	}

	String seckeyAnswer = response.getFieldValue( SEC_WEB_SOCKET_ACCEPT );
	String seckeyChallenge = request.getFieldValue( SEC_WEB_SOCKET_KEY );
	seckeyChallenge = generateFinalKey( seckeyChallenge );

	if( !seckeyChallenge.equals( seckeyAnswer ) ) {
		log.trace("acceptHandshakeAsClient - Wrong key for Sec-WebSocket-Key.");
		return HandshakeState.NOT_MATCHED;
	}

	HandshakeState extensionState= HandshakeState.NOT_MATCHED;
	String requestedExtension = response.getFieldValue(SEC_WEB_SOCKET_EXTENSIONS);
	for( IExtension knownExtension : knownExtensions ) {
		if( knownExtension.acceptProvidedExtensionAsClient( requestedExtension ) ) {
			extension = knownExtension;
			extensionState = HandshakeState.MATCHED;
			log.trace("acceptHandshakeAsClient - Matching extension found: {}",extension);
			break;
		}
	}
	HandshakeState protocolState = HandshakeState.NOT_MATCHED;
	String requestedProtocol = response.getFieldValue(SEC_WEB_SOCKET_PROTOCOL);
	for( IProtocol knownProtocol : knownProtocols ) {
		if( knownProtocol.acceptProvidedProtocol( requestedProtocol ) ) {
			protocol = knownProtocol;
			protocolState = HandshakeState.MATCHED;
			log.trace("acceptHandshakeAsClient - Matching protocol found: {}",protocol);
			break;
		}
	}
	if (protocolState == HandshakeState.MATCHED && extensionState == HandshakeState.MATCHED) {
		return HandshakeState.MATCHED;
	}
	log.trace("acceptHandshakeAsClient - No matching extension or protocol found.");
	return HandshakeState.NOT_MATCHED;
}

public void run() {
	if(thread == null)
		thread = Thread.currentThread();
	interruptableRun();
	thread = null;
}

public void run() {
	if (!doEnsureSingleThread()) {
		return;
	}
	if (!doSetupSelectorAndServerThread()) {
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						continue;
					}

					if( key.isAcceptable() ) {
						doAccept(key, i);
						continue;
					}

					if( key.isReadable() ) {
						if (!doRead(key, i)) {
							continue;
						}
					}

					if( key.isWritable() ) {
						doWrite(key);
					}
				}
				doAdditionalRead();
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				// FIXME controlled shutdown (e.g. take care of buffermanagement)
				return;
			}
		}
	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		doServerShutdown();
	}
}

/**
 * Returns space padding (up to the default max of 30). Use {@link #padding(int, int)} to specify a different limit.
 * @param width amount of padding desired
 * @return string of spaces * width
 * @see #padding(int, int) 
  */
public static String padding(int width) {
    return padding(width, 30);
}

public int read( ByteBuffer dst ) throws IOException {
	if( !isHandShakeComplete() ) {
		processHandshake();
		return 0;
	}
	int amount = 0, limit;
	// test if there was a buffer overflow in dst
	if( inData.hasRemaining() ) {
		return transfereTo( inData, dst );
	}
	// test if some bytes left from last read (e.g. BUFFER_UNDERFLOW)
	if( inCrypt.hasRemaining() ) {
		unwrap();
		amount += transfereTo( inData, dst );
	}
	if( !inCrypt.hasRemaining() )
		inCrypt.clear();
	else
		inCrypt.compact();

	if( sc.read( inCrypt ) == -1 ) {
		return -1;
	}
	inCrypt.flip();
	unwrap();
	amount += transfereTo( inData, dst );
	return amount;

}

/**
 * This method will do whatever necessary to process the sslengine handshake.
 * Thats why it's called both from the {@link #read(ByteBuffer)} and {@link #write(ByteBuffer)}
 **/
private synchronized void processHandshake() throws IOException {
	if( sslEngine.getHandshakeStatus() == HandshakeStatus.NOT_HANDSHAKING )
		return; // since this may be called either from a reading or a writing thread and because this method is synchronized it is necessary to double check if we are still handshaking.
	if( !tasks.isEmpty() ) {
		Iterator<Future<?>> it = tasks.iterator();
		while ( it.hasNext() ) {
			Future<?> f = it.next();
			if( f.isDone() ) {
				it.remove();
			} else {
				if( isBlocking() )
					consumeFutureUninterruptible( f );
				return;
			}
		}
	}

	if( sslEngine.getHandshakeStatus() == SSLEngineResult.HandshakeStatus.NEED_UNWRAP ) {
		if( !isBlocking() || readEngineResult.getStatus() == Status.BUFFER_UNDERFLOW ) {
			inCrypt.compact();
			int read = socketChannel.read( inCrypt );
			if( read == -1 ) {
				throw new IOException( "connection closed unexpectedly by peer" );
			}
			inCrypt.flip();
		}
		inData.compact();
		unwrap();
		if( readEngineResult.getHandshakeStatus() == HandshakeStatus.FINISHED ) {
			createBuffers( sslEngine.getSession() );
			return;
		}
	}
	consumeDelegatedTasks();
	if( tasks.isEmpty() || sslEngine.getHandshakeStatus() == SSLEngineResult.HandshakeStatus.NEED_WRAP ) {
		socketChannel.write( wrap( emptybuffer ) );
		if( writeEngineResult.getHandshakeStatus() == HandshakeStatus.FINISHED ) {
			createBuffers( sslEngine.getSession() );
			return;
		}
	}
	assert ( sslEngine.getHandshakeStatus() != HandshakeStatus.NOT_HANDSHAKING );// this function could only leave NOT_HANDSHAKING after createBuffers was called unless #190 occurs which means that nio wrap/unwrap never return HandshakeStatus.FINISHED

	bufferallocations = 1; // look at variable declaration why this line exists and #190. Without this line buffers would not be be recreated when #190 AND a rehandshake occur.
}

/**
 * Should be called when a Selector has a key that is writable for this
 * WebSocketImpl's SocketChannel connection.
 * 
 * @throws IOException
 *             When socket related I/O errors occur.
 * @throws InterruptedException
 */
public void decode( ByteBuffer socketBuffer ) throws IOException {
	if( !socketBuffer.hasRemaining() )
		return;
	if( DEBUG )
		System.out.println( "process(" + socketBuffer.remaining() + "): {" + ( socketBuffer.remaining() > 1000 ? "too big to display" : new String( socketBuffer.array(), socketBuffer.position(), socketBuffer.remaining() ) ) + "}" );

	if( handshakeComplete ) {
		decodeFrames( socketBuffer );
	} else {
		if( decodeHandshake( socketBuffer ) ) {
			decodeFrames( socketBuffer );
		}
	}
	assert ( isClosing() || isClosed() || !socketBuffer.hasRemaining() );
}

    private void findElements() {
        if (tq.matchChomp("#"))
            byId();
        else if (tq.matchChomp("."))
            byClass();
        else if (tq.matchesWord() || tq.matches("*|"))
            byTag();
        else if (tq.matches("["))
            byAttribute();
        else if (tq.matchChomp("*"))
            allElements();
        else if (tq.matchChomp(":lt("))
            indexLessThan();
        else if (tq.matchChomp(":gt("))
            indexGreaterThan();
        else if (tq.matchChomp(":eq("))
            indexEquals();
        else if (tq.matches(":has("))
            has();
        else if (tq.matches(":contains("))
            contains(false);
        else if (tq.matches(":containsOwn("))
            contains(true);
        else if (tq.matches(":containsWholeText("))
            containsWholeText(false);
        else if (tq.matches(":containsWholeOwnText("))
            containsWholeText(true);
        else if (tq.matches(":containsData("))
            containsData();
        else if (tq.matches(":matches("))
            matches(false);
        else if (tq.matches(":matchesOwn("))
            matches(true);
        else if (tq.matches(":matchesWholeText("))
            matchesWholeText(false);
        else if (tq.matches(":matchesWholeOwnText("))
            matchesWholeText(true);
        else if (tq.matches(":not("))
            not();
		else if (tq.matchChomp(":nth-child("))
        	cssNthChild(false, false);
        else if (tq.matchChomp(":nth-last-child("))
        	cssNthChild(true, false);
        else if (tq.matchChomp(":nth-of-type("))
        	cssNthChild(false, true);
        else if (tq.matchChomp(":nth-last-of-type("))
        	cssNthChild(true, true);
        else if (tq.matchChomp(":first-child"))
        	evals.add(new Evaluator.IsFirstChild());
        else if (tq.matchChomp(":last-child"))
        	evals.add(new Evaluator.IsLastChild());
        else if (tq.matchChomp(":first-of-type"))
        	evals.add(new Evaluator.IsFirstOfType());
        else if (tq.matchChomp(":last-of-type"))
        	evals.add(new Evaluator.IsLastOfType());
        else if (tq.matchChomp(":only-child"))
        	evals.add(new Evaluator.IsOnlyChild());
        else if (tq.matchChomp(":only-of-type"))
        	evals.add(new Evaluator.IsOnlyOfType());
        else if (tq.matchChomp(":empty"))
        	evals.add(new Evaluator.IsEmpty());
        else if (tq.matchChomp(":root"))
        	evals.add(new Evaluator.IsRoot());
        else if (tq.matchChomp(":matchText"))
            evals.add(new Evaluator.MatchText());
		else // unhandled
            throw new Selector.SelectorParseException("Could not parse query '%s': unexpected token at '%s'", query, tq.remainder());

    }

/**
 * Get the {@link FormElement} forms from the selected elements, if any.
 * @return a list of {@link FormElement}s pulled from the matched elements. The list will be empty if the elements contain
 * no forms.
 */
public List<FormElement> forms() {
    return nodesOfType(FormElement.class);
}

void clearFormattingElementsToLastMarker() {
    while (!formattingElements.isEmpty()) {
        Element el = removeLastFormattingElement();
        if (el == null)
            break;
    }
}

boolean process(Token t, HtmlTreeBuilder tb) {
    ArrayList<Element> stack;
    Element el;

    switch (t.type) {
        case Character: {
            Token.Character c = t.asCharacter();
            if (c.getData().equals(nullString)) {
                // todo confirm that check
                tb.error(this);
                return false;
            } else if (tb.framesetOk() && isWhitespace(c)) { // don't check if whitespace if frames already closed
                tb.reconstructFormattingElements();
                tb.insert(c);
            } else {
                tb.reconstructFormattingElements();
                tb.insert(c);
                tb.framesetOk(false);
            }
            break;
        }
        case Comment: {
            tb.insert(t.asComment());
            break;
        }
        case Doctype: {
            tb.error(this);
            return false;
        }
        case StartTag:
            Token.StartTag startTag = t.asStartTag();
            String name = startTag.normalName();

            switch (name) {
                case "a":
                    if (tb.getActiveFormattingElement("a") != null) {
                        tb.error(this);
                        tb.processEndTag("a");

                        // still on stack?
                        Element remainingA = tb.getFromStack("a");
                        if (remainingA != null) {
                            tb.removeFromActiveFormattingElements(remainingA);
                            tb.removeFromStack(remainingA);
                        }
                    }
                    tb.reconstructFormattingElements();
                    Element a = tb.insert(startTag);
                    tb.pushActiveFormattingElements(a);
                    break;
                case "span":
                    // same as final else, but short circuits lots of checks
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    break;
                case "li":
                    tb.framesetOk(false);
                    stack = tb.getStack();
                    for (int i = stack.size() - 1; i > 0; i--) {
                        el = stack.get(i);
                        if (el.normalName().equals("li")) {
                            tb.processEndTag("li");
                            break;
                        }
                        if (tb.isSpecial(el) && !StringUtil.inSorted(el.normalName(), Constants.InBodyStartLiBreakers))
                            break;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    break;
                case "html":
                    tb.error(this);
                    // merge attributes onto real html
                    Element html = tb.getStack().get(0);
                    for (Attribute attribute : startTag.getAttributes()) {
                        if (!html.hasAttr(attribute.getKey()))
                            html.attributes().put(attribute);
                    }
                    break;
                case "body":
                    tb.error(this);
                    stack = tb.getStack();
                    if (stack.size() == 1 || (stack.size() > 2 && !stack.get(1).normalName().equals("body"))) {
                        // only in fragment case
                        return false; // ignore
                    } else {
                        tb.framesetOk(false);
                        Element body = stack.get(1);
                        for (Attribute attribute : startTag.getAttributes()) {
                            if (!body.hasAttr(attribute.getKey()))
                                body.attributes().put(attribute);
                        }
                    }
                    break;
                case "frameset":
                    tb.error(this);
                    stack = tb.getStack();
                    if (stack.size() == 1 || (stack.size() > 2 && !stack.get(1).normalName().equals("body"))) {
                        // only in fragment case
                        return false; // ignore
                    } else if (!tb.framesetOk()) {
                        return false; // ignore frameset
                    } else {
                        Element second = stack.get(1);
                        if (second.parent() != null)
                            second.remove();
                        // pop up to html element
                        while (stack.size() > 1)
                            stack.remove(stack.size() - 1);
                        tb.insert(startTag);
                        tb.transition(InFrameset);
                    }
                    break;
                case "form":
                    if (tb.getFormElement() != null) {
                        tb.error(this);
                        return false;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insertForm(startTag, true);
                    break;
                case "plaintext":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.tokeniser.transition(TokeniserState.PLAINTEXT); // once in, never gets out
                    break;
                case "button":
                    if (tb.inButtonScope("button")) {
                        // close and reprocess
                        tb.error(this);
                        tb.processEndTag("button");
                        tb.process(startTag);
                    } else {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                        tb.framesetOk(false);
                    }
                    break;
                case "nobr":
                    tb.reconstructFormattingElements();
                    if (tb.inScope("nobr")) {
                        tb.error(this);
                        tb.processEndTag("nobr");
                        tb.reconstructFormattingElements();
                    }
                    el = tb.insert(startTag);
                    tb.pushActiveFormattingElements(el);
                    break;
                case "table":
                    if (tb.getDocument().quirksMode() != Document.QuirksMode.quirks && tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.framesetOk(false);
                    tb.transition(InTable);
                    break;
                case "input":
                    tb.reconstructFormattingElements();
                    el = tb.insertEmpty(startTag);
                    if (!el.attr("type").equalsIgnoreCase("hidden"))
                        tb.framesetOk(false);
                    break;
                case "hr":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insertEmpty(startTag);
                    tb.framesetOk(false);
                    break;
                case "image":
                    if (tb.getFromStack("svg") == null)
                        return tb.process(startTag.name("img")); // change <image> to <img>, unless in svg
                    else
                        tb.insert(startTag);
                    break;
                case "isindex":
                    // how much do we care about the early 90s?
                    tb.error(this);
                    if (tb.getFormElement() != null)
                        return false;

                    tb.processStartTag("form");
                    if (startTag.attributes.hasKey("action")) {
                        Element form = tb.getFormElement();
                        form.attr("action", startTag.attributes.get("action"));
                    }
                    tb.processStartTag("hr");
                    tb.processStartTag("label");
                    // hope you like english.
                    String prompt = startTag.attributes.hasKey("prompt") ?
                        startTag.attributes.get("prompt") :
                        "This is a searchable index. Enter search keywords: ";

                    tb.process(new Token.Character().data(prompt));

                    // input
                    Attributes inputAttribs = new Attributes();
                    for (Attribute attr : startTag.attributes) {
                        if (!StringUtil.inSorted(attr.getKey(), Constants.InBodyStartInputAttribs))
                            inputAttribs.put(attr);
                    }
                    inputAttribs.put("name", "isindex");
                    tb.processStartTag("input", inputAttribs);
                    tb.processEndTag("label");
                    tb.processStartTag("hr");
                    tb.processEndTag("form");
                    break;
                case "textarea":
                    tb.insert(startTag);
                    if (!startTag.isSelfClosing()) {
                        tb.tokeniser.transition(TokeniserState.Rcdata);
                        tb.markInsertionMode();
                        tb.framesetOk(false);
                        tb.transition(Text);
                    }
                    break;
                case "xmp":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.reconstructFormattingElements();
                    tb.framesetOk(false);
                    handleRawtext(startTag, tb);
                    break;
                case "iframe":
                    tb.framesetOk(false);
                    handleRawtext(startTag, tb);
                    break;
                case "noembed":
                    // also handle noscript if script enabled
                    handleRawtext(startTag, tb);
                    break;
                case "select":
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    tb.framesetOk(false);

                    HtmlTreeBuilderState state = tb.state();
                    if (state.equals(InTable) || state.equals(InCaption) || state.equals(InTableBody) || state.equals(InRow) || state.equals(InCell))
                        tb.transition(InSelectInTable);
                    else
                        tb.transition(InSelect);
                    break;
                case "math":
                    tb.reconstructFormattingElements();
                    // todo: handle A start tag whose tag name is "math" (i.e. foreign, mathml)
                    tb.insert(startTag);
                    break;
                case "svg":
                    tb.reconstructFormattingElements();
                    // todo: handle A start tag whose tag name is "svg" (xlink, svg)
                    tb.insert(startTag);
                    break;
                // static final String[] Headings = new String[]{"h1", "h2", "h3", "h4", "h5", "h6"};
                case "h1":
                case "h2":
                case "h3":
                case "h4":
                case "h5":
                case "h6":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    if (StringUtil.inSorted(tb.currentElement().normalName(), Constants.Headings)) {
                        tb.error(this);
                        tb.pop();
                    }
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartPreListing = new String[]{"listing", "pre"};
                case "pre":
                case "listing":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.reader.matchConsume("\n"); // ignore LF if next token
                    tb.framesetOk(false);
                    break;
                // static final String[] DdDt = new String[]{"dd", "dt"};
                case "dd":
                case "dt":
                    tb.framesetOk(false);
                    stack = tb.getStack();
                    for (int i = stack.size() - 1; i > 0; i--) {
                        el = stack.get(i);
                        if (StringUtil.inSorted(el.normalName(), Constants.DdDt)) {
                            tb.processEndTag(el.normalName());
                            break;
                        }
                        if (tb.isSpecial(el) && !StringUtil.inSorted(el.normalName(), Constants.InBodyStartLiBreakers))
                            break;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartOptions = new String[]{"optgroup", "option"};
                case "optgroup":
                case "option":
                    if (tb.currentElement().normalName().equals("option"))
                        tb.processEndTag("option");
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartRuby = new String[]{"rp", "rt"};
                case "rp":
                case "rt":
                    if (tb.inScope("ruby")) {
                        tb.generateImpliedEndTags();
                        if (!tb.currentElement().normalName().equals("ruby")) {
                            tb.error(this);
                            tb.popStackToBefore("ruby"); // i.e. close up to but not include name
                        }
                        tb.insert(startTag);
                    }
                    // todo - is this right? drops rp, rt if ruby not in scope?
                    break;
                default:
                    // todo - bring scan groups in if desired
                    if (StringUtil.inSorted(name, Constants.InBodyStartEmptyFormatters)) {
                        tb.reconstructFormattingElements();
                        tb.insertEmpty(startTag);
                        tb.framesetOk(false);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartPClosers)) {
                        if (tb.inButtonScope("p")) {
                            tb.processEndTag("p");
                        }
                        tb.insert(startTag);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartToHead)) {
                        return tb.process(t, InHead);
                    } else if (StringUtil.inSorted(name, Constants.Formatters)) {
                        tb.reconstructFormattingElements();
                        el = tb.insert(startTag);
                        tb.pushActiveFormattingElements(el);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                        tb.insertMarkerToFormattingElements();
                        tb.framesetOk(false);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartMedia)) {
                        tb.insertEmpty(startTag);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartDrop)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                    }
            }
            break;

        case EndTag:
            Token.EndTag endTag = t.asEndTag();
            name = endTag.normalName();
            switch (name) {
                case "sarcasm": // *sigh*
                case "span":
                    // same as final fall through, but saves short circuit
                    return anyOtherEndTag(t, tb);
                case "li":
                    if (!tb.inListItemScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "body":
                    if (!tb.inScope("body")) {
                        tb.error(this);
                        return false;
                    } else {
                        // todo: error if stack contains something not dd, dt, li, optgroup, option, p, rp, rt, tbody, td, tfoot, th, thead, tr, body, html
                        tb.transition(AfterBody);
                    }
                    break;
                case "html":
                    boolean notIgnored = tb.processEndTag("body");
                    if (notIgnored)
                        return tb.process(endTag);
                    break;
                case "form":
                    Element currentForm = tb.getFormElement();
                    tb.setFormElement(null);
                    if (currentForm == null || !tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags();
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        // remove currentForm from stack. will shift anything under up.
                        tb.removeFromStack(currentForm);
                    }
                    break;
                case "p":
                    if (!tb.inButtonScope(name)) {
                        tb.error(this);
                        tb.processStartTag(name); // if no p to close, creates an empty <p></p>
                        return tb.process(endTag);
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "dd":
                case "dt":
                    if (!tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "h1":
                case "h2":
                case "h3":
                case "h4":
                case "h5":
                case "h6":
                    if (!tb.inScope(Constants.Headings)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(Constants.Headings);
                    }
                    break;
                case "br":
                    tb.error(this);
                    tb.processStartTag("br");
                    return false;
                default:
                    // todo - move rest to switch if desired
                    if (StringUtil.inSorted(name, Constants.InBodyEndAdoptionFormatters)) {
                        // Adoption Agency Algorithm.
                        for (int i = 0; i < 8; i++) {
                            Element formatEl = tb.getActiveFormattingElement(name);
                            if (formatEl == null)
                                return anyOtherEndTag(t, tb);
                            else if (!tb.onStack(formatEl)) {
                                tb.error(this);
                                tb.removeFromActiveFormattingElements(formatEl);
                                return true;
                            } else if (!tb.inScope(formatEl.normalName())) {
                                tb.error(this);
                                return false;
                            } else if (tb.currentElement() != formatEl)
                                tb.error(this);

                            Element furthestBlock = null;
                            Element commonAncestor = null;
                            boolean seenFormattingElement = false;
                            stack = tb.getStack();
                            // the spec doesn't limit to < 64, but in degenerate cases (9000+ stack depth) this prevents
                            // run-aways
                            final int stackSize = stack.size();
                            for (int si = 0; si < stackSize && si < 64; si++) {
                                el = stack.get(si);
                                if (el == formatEl) {
                                    commonAncestor = stack.get(si - 1);
                                    seenFormattingElement = true;
                                } else if (seenFormattingElement && tb.isSpecial(el)) {
                                    furthestBlock = el;
                                    break;
                                }
                            }
                            if (furthestBlock == null) {
                                tb.popStackToClose(formatEl.normalName());
                                tb.removeFromActiveFormattingElements(formatEl);
                                return true;
                            }

                            // todo: Let a bookmark note the position of the formatting element in the list of active formatting elements relative to the elements on either side of it in the list.
                            // does that mean: int pos of format el in list?
                            Element node = furthestBlock;
                            Element lastNode = furthestBlock;
                            for (int j = 0; j < 3; j++) {
                                if (tb.onStack(node))
                                    node = tb.aboveOnStack(node);
                                if (!tb.isInActiveFormattingElements(node)) { // note no bookmark check
                                    tb.removeFromStack(node);
                                    continue;
                                } else if (node == formatEl)
                                    break;

                                Element replacement = new Element(Tag.valueOf(node.nodeName(), ParseSettings.preserveCase), tb.getBaseUri());
                                // case will follow the original node (so honours ParseSettings)
                                tb.replaceActiveFormattingElement(node, replacement);
                                tb.replaceOnStack(node, replacement);
                                node = replacement;

                                //noinspection StatementWithEmptyBody
                                if (lastNode == furthestBlock) {
                                    // todo: move the aforementioned bookmark to be immediately after the new node in the list of active formatting elements.
                                    // not getting how this bookmark both straddles the element above, but is inbetween here...
                                }
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                node.appendChild(lastNode);

                                lastNode = node;
                            }

                            if (StringUtil.inSorted(commonAncestor.normalName(), Constants.InBodyEndTableFosters)) {
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                tb.insertInFosterParent(lastNode);
                            } else {
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                commonAncestor.appendChild(lastNode);
                            }

                            Element adopter = new Element(formatEl.tag(), tb.getBaseUri());
                            adopter.attributes().addAll(formatEl.attributes());
                            Node[] childNodes = furthestBlock.childNodes().toArray(new Node[0]);
                            for (Node childNode : childNodes) {
                                adopter.appendChild(childNode); // append will reparent. thus the clone to avoid concurrent mod.
                            }
                            furthestBlock.appendChild(adopter);
                            tb.removeFromActiveFormattingElements(formatEl);
                            // todo: insert the new element into the list of active formatting elements at the position of the aforementioned bookmark.
                            tb.removeFromStack(formatEl);
                            tb.insertOnStackAfter(furthestBlock, adopter);
                        }
                    } else if (StringUtil.inSorted(name, Constants.InBodyEndClosers)) {
                        if (!tb.inScope(name)) {
                            // nothing to close
                            tb.error(this);
                            return false;
                        } else {
                            tb.generateImpliedEndTags();
                            if (!tb.currentElement().normalName().equals(name))
                                tb.error(this);
                            tb.popStackToClose(name);
                        }
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                        if (!tb.inScope("name")) {
                            if (!tb.inScope(name)) {
                                tb.error(this);
                                return false;
                            }
                            tb.generateImpliedEndTags();
                            if (!tb.currentElement().normalName().equals(name))
                                tb.error(this);
                            tb.popStackToClose(name);
                            tb.clearFormattingElementsToLastMarker();
                        }
                    } else {
                        return anyOtherEndTag(t, tb);
                    }
            }
            break;
        case EOF:
            // todo: error if stack contains something not dd, dt, li, p, tbody, td, tfoot, th, thead, tr, body, html
            // stop parsing
            break;
    }
    return true;
}

boolean process(Token t, HtmlTreeBuilder tb) {
    ArrayList<Element> stack;
    Element el;

    switch (t.type) {
        case Character: {
            Token.Character c = t.asCharacter();
            if (c.getData().equals(nullString)) {
                // todo confirm that check
                tb.error(this);
                return false;
            } else if (tb.framesetOk() && isWhitespace(c)) { // don't check if whitespace if frames already closed
                tb.reconstructFormattingElements();
                tb.insert(c);
            } else {
                tb.reconstructFormattingElements();
                tb.insert(c);
                tb.framesetOk(false);
            }
            break;
        }
        case Comment: {
            tb.insert(t.asComment());
            break;
        }
        case Doctype: {
            tb.error(this);
            return false;
        }
        case StartTag:
            Token.StartTag startTag = t.asStartTag();
            String name = startTag.normalName();

            switch (name) {
                case "a":
                    if (tb.getActiveFormattingElement("a") != null) {
                        tb.error(this);
                        tb.processEndTag("a");

                        // still on stack?
                        Element remainingA = tb.getFromStack("a");
                        if (remainingA != null) {
                            tb.removeFromActiveFormattingElements(remainingA);
                            tb.removeFromStack(remainingA);
                        }
                    }
                    tb.reconstructFormattingElements();
                    Element a = tb.insert(startTag);
                    tb.pushActiveFormattingElements(a);
                    break;
                case "span":
                    // same as final else, but short circuits lots of checks
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    break;
                case "li":
                    tb.framesetOk(false);
                    stack = tb.getStack();
                    for (int i = stack.size() - 1; i > 0; i--) {
                        el = stack.get(i);
                        if (el.normalName().equals("li")) {
                            tb.processEndTag("li");
                            break;
                        }
                        if (tb.isSpecial(el) && !StringUtil.inSorted(el.normalName(), Constants.InBodyStartLiBreakers))
                            break;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    break;
                case "html":
                    tb.error(this);
                    // merge attributes onto real html
                    Element html = tb.getStack().get(0);
                    for (Attribute attribute : startTag.getAttributes()) {
                        if (!html.hasAttr(attribute.getKey()))
                            html.attributes().put(attribute);
                    }
                    break;
                case "body":
                    tb.error(this);
                    stack = tb.getStack();
                    if (stack.size() == 1 || (stack.size() > 2 && !stack.get(1).normalName().equals("body"))) {
                        // only in fragment case
                        return false; // ignore
                    } else {
                        tb.framesetOk(false);
                        Element body = stack.get(1);
                        for (Attribute attribute : startTag.getAttributes()) {
                            if (!body.hasAttr(attribute.getKey()))
                                body.attributes().put(attribute);
                        }
                    }
                    break;
                case "frameset":
                    tb.error(this);
                    stack = tb.getStack();
                    if (stack.size() == 1 || (stack.size() > 2 && !stack.get(1).normalName().equals("body"))) {
                        // only in fragment case
                        return false; // ignore
                    } else if (!tb.framesetOk()) {
                        return false; // ignore frameset
                    } else {
                        Element second = stack.get(1);
                        if (second.parent() != null)
                            second.remove();
                        // pop up to html element
                        while (stack.size() > 1)
                            stack.remove(stack.size() - 1);
                        tb.insert(startTag);
                        tb.transition(InFrameset);
                    }
                    break;
                case "form":
                    if (tb.getFormElement() != null) {
                        tb.error(this);
                        return false;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insertForm(startTag, true);
                    break;
                case "plaintext":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.tokeniser.transition(TokeniserState.PLAINTEXT); // once in, never gets out
                    break;
                case "button":
                    if (tb.inButtonScope("button")) {
                        // close and reprocess
                        tb.error(this);
                        tb.processEndTag("button");
                        tb.process(startTag);
                    } else {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                        tb.framesetOk(false);
                    }
                    break;
                case "nobr":
                    tb.reconstructFormattingElements();
                    if (tb.inScope("nobr")) {
                        tb.error(this);
                        tb.processEndTag("nobr");
                        tb.reconstructFormattingElements();
                    }
                    el = tb.insert(startTag);
                    tb.pushActiveFormattingElements(el);
                    break;
                case "table":
                    if (tb.getDocument().quirksMode() != Document.QuirksMode.quirks && tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.framesetOk(false);
                    tb.transition(InTable);
                    break;
                case "input":
                    tb.reconstructFormattingElements();
                    el = tb.insertEmpty(startTag);
                    if (!el.attr("type").equalsIgnoreCase("hidden"))
                        tb.framesetOk(false);
                    break;
                case "hr":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
