                    for (Attribute attr : startTag.attributes) {
                        if (!StringUtil.inSorted(attr.getKey(), Constants.InBodyStartInputAttribs))
                            inputAttribs.put(attr);
                    }
                    inputAttribs.put("name", "isindex");
                    tb.processStartTag("input", inputAttribs);
                    tb.processEndTag("label");
                    tb.processStartTag("hr");
                    tb.processEndTag("form");
                    break;
                case "textarea":
                    tb.insert(startTag);
                    if (!startTag.isSelfClosing()) {
                        tb.tokeniser.transition(TokeniserState.Rcdata);
                        tb.markInsertionMode();
                        tb.framesetOk(false);
                        tb.transition(Text);
                    }
                    break;
                case "xmp":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.reconstructFormattingElements();
                    tb.framesetOk(false);
                    handleRawtext(startTag, tb);
                    break;
                case "iframe":
                    tb.framesetOk(false);
                    handleRawtext(startTag, tb);
                    break;
                case "noembed":
                    // also handle noscript if script enabled
                    handleRawtext(startTag, tb);
                    break;
                case "select":
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    tb.framesetOk(false);

                    HtmlTreeBuilderState state = tb.state();
                    if (state.equals(InTable) || state.equals(InCaption) || state.equals(InTableBody) || state.equals(InRow) || state.equals(InCell))
                        tb.transition(InSelectInTable);
                    else
                        tb.transition(InSelect);
                    break;
                case "math":
                    tb.reconstructFormattingElements();
                    // todo: handle A start tag whose tag name is "math" (i.e. foreign, mathml)
                    tb.insert(startTag);
                    break;
                case "svg":
                    tb.reconstructFormattingElements();
                    // todo: handle A start tag whose tag name is "svg" (xlink, svg)
                    tb.insert(startTag);
                    break;
                // static final String[] Headings = new String[]{"h1", "h2", "h3", "h4", "h5", "h6"};
                case "h1":
                case "h2":
                case "h3":
                case "h4":
                case "h5":
                case "h6":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    if (StringUtil.inSorted(tb.currentElement().normalName(), Constants.Headings)) {
                        tb.error(this);
                        tb.pop();
                    }
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartPreListing = new String[]{"listing", "pre"};
                case "pre":
                case "listing":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.reader.matchConsume("\n"); // ignore LF if next token
                    tb.framesetOk(false);
                    break;
                // static final String[] DdDt = new String[]{"dd", "dt"};
                case "dd":
                case "dt":
                    tb.framesetOk(false);
                    stack = tb.getStack();
                    for (int i = stack.size() - 1; i > 0; i--) {
                        el = stack.get(i);
                        if (StringUtil.inSorted(el.normalName(), Constants.DdDt)) {
                            tb.processEndTag(el.normalName());
                            break;
                        }
                        if (tb.isSpecial(el) && !StringUtil.inSorted(el.normalName(), Constants.InBodyStartLiBreakers))
                            break;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartOptions = new String[]{"optgroup", "option"};
                case "optgroup":
                case "option":
                    if (tb.currentElement().normalName().equals("option"))
                        tb.processEndTag("option");
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartRuby = new String[]{"rp", "rt"};
                case "rp":
                case "rt":
                    if (tb.inScope("ruby")) {
                        tb.generateImpliedEndTags();
                        if (!tb.currentElement().normalName().equals("ruby")) {
                            tb.error(this);
                            tb.popStackToBefore("ruby"); // i.e. close up to but not include name
                        }
                        tb.insert(startTag);
                    }
                    // todo - is this right? drops rp, rt if ruby not in scope?
                    break;
                default:
                    // todo - bring scan groups in if desired
                    if (StringUtil.inSorted(name, Constants.InBodyStartEmptyFormatters)) {
                        tb.reconstructFormattingElements();
                        tb.insertEmpty(startTag);
                        tb.framesetOk(false);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartPClosers)) {
                        if (tb.inButtonScope("p")) {
                            tb.processEndTag("p");
                        }
                        tb.insert(startTag);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartToHead)) {
                        return tb.process(t, InHead);
                    } else if (StringUtil.inSorted(name, Constants.Formatters)) {
                        tb.reconstructFormattingElements();
                        el = tb.insert(startTag);
                        tb.pushActiveFormattingElements(el);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                        tb.insertMarkerToFormattingElements();
                        tb.framesetOk(false);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartMedia)) {
                        tb.insertEmpty(startTag);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartDrop)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                    }
            }
            break;

        case EndTag:
            Token.EndTag endTag = t.asEndTag();
            name = endTag.normalName();
            switch (name) {
                case "sarcasm": // *sigh*
                case "span":
                    // same as final fall through, but saves short circuit
                    return anyOtherEndTag(t, tb);
                case "li":
                    if (!tb.inListItemScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "body":
                    if (!tb.inScope("body")) {
                        tb.error(this);
                        return false;
                    } else {
                        // todo: error if stack contains something not dd, dt, li, optgroup, option, p, rp, rt, tbody, td, tfoot, th, thead, tr, body, html
                        tb.transition(AfterBody);
                    }
                    break;
                case "html":
                    boolean notIgnored = tb.processEndTag("body");
                    if (notIgnored)
                        return tb.process(endTag);
                    break;
                case "form":
                    Element currentForm = tb.getFormElement();
                    tb.setFormElement(null);
                    if (currentForm == null || !tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags();
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        // remove currentForm from stack. will shift anything under up.
                        tb.removeFromStack(currentForm);
                    }
                    break;
                case "p":
                    if (!tb.inButtonScope(name)) {
                        tb.error(this);
                        tb.processStartTag(name); // if no p to close, creates an empty <p></p>
                        return tb.process(endTag);
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "dd":
                case "dt":
                    if (!tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "h1":
                case "h2":
                case "h3":
                case "h4":
                case "h5":
                case "h6":
                    if (!tb.inScope(Constants.Headings)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(Constants.Headings);
                    }
                    break;
                case "br":
                    tb.error(this);
                    tb.processStartTag("br");
                    return false;
                default:
                    // todo - move rest to switch if desired
                    if (StringUtil.inSorted(name, Constants.InBodyEndAdoptionFormatters)) {
                        // Adoption Agency Algorithm.
                        for (int i = 0; i < 8; i++) {
                            Element formatEl = tb.getActiveFormattingElement(name);
                            if (formatEl == null)
                                return anyOtherEndTag(t, tb);
                            else if (!tb.onStack(formatEl)) {
                                tb.error(this);
                                tb.removeFromActiveFormattingElements(formatEl);
                                return true;
                            } else if (!tb.inScope(formatEl.normalName())) {
                                tb.error(this);
                                return false;
                            } else if (tb.currentElement() != formatEl)
                                tb.error(this);

                            Element furthestBlock = null;
                            Element commonAncestor = null;
                            boolean seenFormattingElement = false;
                            stack = tb.getStack();
                            // the spec doesn't limit to < 64, but in degenerate cases (9000+ stack depth) this prevents
                            // run-aways
                            final int stackSize = stack.size();
                            for (int si = 0; si < stackSize && si < 64; si++) {
                                el = stack.get(si);
                                if (el == formatEl) {
                                    commonAncestor = stack.get(si - 1);
                                    seenFormattingElement = true;
                                } else if (seenFormattingElement && tb.isSpecial(el)) {
                                    furthestBlock = el;
                                    break;
                                }
                            }
                            if (furthestBlock == null) {
                                tb.popStackToClose(formatEl.normalName());
                                tb.removeFromActiveFormattingElements(formatEl);
                                return true;
                            }

                            // todo: Let a bookmark note the position of the formatting element in the list of active formatting elements relative to the elements on either side of it in the list.
                            // does that mean: int pos of format el in list?
                            Element node = furthestBlock;
                            Element lastNode = furthestBlock;
                            for (int j = 0; j < 3; j++) {
                                if (tb.onStack(node))
                                    node = tb.aboveOnStack(node);
                                if (!tb.isInActiveFormattingElements(node)) { // note no bookmark check
                                    tb.removeFromStack(node);
                                    continue;
                                } else if (node == formatEl)
                                    break;

                                Element replacement = new Element(Tag.valueOf(node.nodeName(), ParseSettings.preserveCase), tb.getBaseUri());
                                // case will follow the original node (so honours ParseSettings)
                                tb.replaceActiveFormattingElement(node, replacement);
                                tb.replaceOnStack(node, replacement);
                                node = replacement;

                                //noinspection StatementWithEmptyBody
                                if (lastNode == furthestBlock) {
                                    // todo: move the aforementioned bookmark to be immediately after the new node in the list of active formatting elements.
                                    // not getting how this bookmark both straddles the element above, but is inbetween here...
                                }
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                node.appendChild(lastNode);

                                lastNode = node;
                            }

                            if (StringUtil.inSorted(commonAncestor.normalName(), Constants.InBodyEndTableFosters)) {
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                tb.insertInFosterParent(lastNode);
                            } else {
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                commonAncestor.appendChild(lastNode);
                            }

                            Element adopter = new Element(formatEl.tag(), tb.getBaseUri());
                            adopter.attributes().addAll(formatEl.attributes());
                            Node[] childNodes = furthestBlock.childNodes().toArray(new Node[0]);
                            for (Node childNode : childNodes) {
                                adopter.appendChild(childNode); // append will reparent. thus the clone to avoid concurrent mod.
                            }
                            furthestBlock.appendChild(adopter);
                            tb.removeFromActiveFormattingElements(formatEl);
                            // todo: insert the new element into the list of active formatting elements at the position of the aforementioned bookmark.
                            tb.removeFromStack(formatEl);
                            tb.insertOnStackAfter(furthestBlock, adopter);
                        }
                    } else if (StringUtil.inSorted(name, Constants.InBodyEndClosers)) {
                        if (!tb.inScope(name)) {
                            // nothing to close
                            tb.error(this);
                            return false;
                        } else {
                            tb.generateImpliedEndTags();
                            if (!tb.currentElement().normalName().equals(name))
                                tb.error(this);
                            tb.popStackToClose(name);
                        }
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                        if (!tb.inScope("name")) {
                            if (!tb.inScope(name)) {
                                tb.error(this);
                                return false;
                            }
                            tb.generateImpliedEndTags();
                            if (!tb.currentElement().normalName().equals(name))
                                tb.error(this);
                            tb.popStackToClose(name);
                            tb.clearFormattingElementsToLastMarker();
                        }
                    } else {
                        return anyOtherEndTag(t, tb);
                    }
            }
            break;
        case EOF:
            // todo: error if stack contains something not dd, dt, li, p, tbody, td, tfoot, th, thead, tr, body, html
            // stop parsing
            break;
    }
    return true;
}

public String html() {
    StringBuilder accum = new StringBuilder();
    accum
            .append("<")
            .append(tagName())
            .append(attributes.html());

    if (childNodes.isEmpty() && tag.isEmpty()) {
        accum.append(" />");
    } else {
        accum.append(">");
        for (Node node : childNodes)
            accum.append(node.html());
        accum.append("</").append(tagName()).append(">");
    }

    return accum.toString();
}

public void run() {
  InputStream istream;
  try {
    boolean upgradeSocketToSSLSocket = prepareSocket();

    socket.setTcpNoDelay(isTcpNoDelay());
    socket.setReuseAddress(isReuseAddr());

    if (!socket.isConnected()) {
      InetSocketAddress addr = new InetSocketAddress(dnsResolver.resolve(uri), this.getPort());
      socket.connect(addr, connectTimeout);
    }

    // if the socket is set by others we don't apply any TLS wrapper
    if (upgradeSocketToSSLSocket && "wss".equals(uri.getScheme())) {
      upgradeSocketToSSL();
    }

    if (socket instanceof SSLSocket) {
      SSLSocket sslSocket = (SSLSocket) socket;
      SSLParameters sslParameters = sslSocket.getSSLParameters();
      onSetSSLParameters(sslParameters);
      sslSocket.setSSLParameters(sslParameters);
    }

    istream = socket.getInputStream();
    ostream = socket.getOutputStream();

    sendHandshake();
  } catch (/*IOException | SecurityException | UnresolvedAddressException | InvalidHandshakeException | ClosedByInterruptException | SocketTimeoutException */Exception e) {
    onWebsocketError(engine, e);
    engine.closeConnection(CloseFrame.NEVER_CONNECTED, e.getMessage());
    return;
  } catch (InternalError e) {
    // https://bugs.openjdk.java.net/browse/JDK-8173620
    if (e.getCause() instanceof InvocationTargetException && e.getCause()
        .getCause() instanceof IOException) {
      IOException cause = (IOException) e.getCause().getCause();
      onWebsocketError(engine, cause);
      engine.closeConnection(CloseFrame.NEVER_CONNECTED, cause.getMessage());
      return;
    }
    throw e;
  }

  writeThread = new Thread(new WebsocketWriteThread(this));
  writeThread.start();

  byte[] rawbuffer = new byte[WebSocketImpl.RCVBUF];
  int readBytes;

  try {
    while (!isClosing() && !isClosed() && (readBytes = istream.read(rawbuffer)) != -1) {
      engine.decode(ByteBuffer.wrap(rawbuffer, 0, readBytes));
    }
    engine.eot();
  } catch (IOException e) {
    handleIOException(e);
  } catch (RuntimeException e) {
    // this catch case covers internal errors only and indicates a bug in this websocket implementation
    onError(e);
    engine.closeConnection(CloseFrame.ABNORMAL_CLOSE, e.getMessage());
  }
  connectReadThread = null;
}

Element insert(final Token.StartTag startTag) {
    dedupeAttributes(startTag);

    // handle empty unknown tags
    // when the spec expects an empty tag, will directly hit insertEmpty, so won't generate this fake end tag.
    if (startTag.isSelfClosing()) {
        Element el = insertEmpty(startTag);
        stack.add(el);
        tokeniser.transition(TokeniserState.Data); // handles <script />, otherwise needs breakout steps from script data
        tokeniser.emit(emptyEnd.reset().name(el.tagName()));  // ensure we get out of whatever state we are in. emitted for yielded processing
        return el;
    }

    Element el = new Element(tagFor(startTag.name(), settings), null, settings.normalizeAttributes(startTag.attributes));
    insert(el, startTag);
    return el;
}

public void run() {
  running = tryToConnect(new InetSocketAddress(uri.getHost(), getPort()));

  while (this.running) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while (i.hasNext()) {
        SelectionKey key = i.next();
        i.remove();

        if (key.isConnectable()) {
          finishConnect();
        }

        if (key.isReadable()) {
          conn.handleRead();
        }
      }
    } catch (IOException ex) {
  	  onIOError(ex);
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketClient thread ended!");
}

private boolean inBodyEndTag(Token t, HtmlTreeBuilder tb) {
    final Token.EndTag endTag = t.asEndTag();
    final String name = endTag.normalName();

    switch (name) {
        case "sarcasm": // *sigh*
        case "span":
            // same as final fall through, but saves short circuit
            return anyOtherEndTag(t, tb);
        case "li":
            if (!tb.inListItemScope(name)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(name);
            }
            break;
        case "body":
            if (!tb.inScope("body")) {
                tb.error(this);
                return false;
            } else {
                // todo: error if stack contains something not dd, dt, li, optgroup, option, p, rp, rt, tbody, td, tfoot, th, thead, tr, body, html
                tb.transition(AfterBody);
            }
            break;
        case "html":
            boolean notIgnored = tb.processEndTag("body");
            if (notIgnored)
                return tb.process(endTag);
            break;
        case "form":
            Element currentForm = tb.getFormElement();
            tb.setFormElement(null);
            if (currentForm == null || !tb.inScope(name)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags();
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                // remove currentForm from stack. will shift anything under up.
                tb.removeFromStack(currentForm);
            }
            break;
        case "p":
            if (!tb.inButtonScope(name)) {
                tb.error(this);
                tb.processStartTag(name); // if no p to close, creates an empty <p></p>
                return tb.process(endTag);
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(name);
            }
            break;
        case "dd":
        case "dt":
            if (!tb.inScope(name)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(name);
            }
            break;
        case "h1":
        case "h2":
        case "h3":
        case "h4":
        case "h5":
        case "h6":
            if (!tb.inScope(Constants.Headings)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(Constants.Headings);
            }
            break;
        case "br":
            tb.error(this);
            tb.processStartTag("br");
            return false;
        default:
            // todo - move rest to switch if desired
            if (StringUtil.inSorted(name, Constants.InBodyEndAdoptionFormatters)) {
                return inBodyEndTagAdoption(t, tb);
            } else if (StringUtil.inSorted(name, Constants.InBodyEndClosers)) {
                if (!tb.inScope(name)) {
                    // nothing to close
                    tb.error(this);
                    return false;
                } else {
                    tb.generateImpliedEndTags();
                    if (!tb.currentElement().normalName().equals(name))
                        tb.error(this);
                    tb.popStackToClose(name);
                }
            } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                if (!tb.inScope("name")) {
                    if (!tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    }
                    tb.generateImpliedEndTags();
                    if (!tb.currentElement().normalName().equals(name))
                        tb.error(this);
                    tb.popStackToClose(name);
                    tb.clearFormattingElementsToLastMarker();
                }
            } else {
                return anyOtherEndTag(t, tb);
            }
    }
    return true;
}

/**
 * Change (rename) the tag of this element. For example, convert a {@code <span>} to a {@code <div>} with
 * {@code el.tagName("div");}.
 *
 * @param tagName new tag name for this element
 * @return this element, for chaining
 * @see Elements#tagName(String)
 */
public Element tagName(String tagName) {
    Validate.notEmptyParam(tagName, "tagName");
    tag = Tag.valueOf(tagName, NodeUtils.parser(this).settings()); // maintains the case option of the original parse
    return this;
}

/**
 * This will close the connection immediately without a proper close handshake.
 * The code and the message therefore won't be transfered over the wire also they will be forwarded to onClose/onWebsocketClose.
 *
 * @param code    the closing code
 * @param message the closing message
 * @param remote  Indicates who "generated" <code>code</code>.<br>
 *                <code>true</code> means that this endpoint received the <code>code</code> from the other endpoint.<br>
 *                false means this endpoint decided to send the given code,<br>
 *                <code>remote</code> may also be true if this endpoint started the closing handshake since the other endpoint may not simply echo the <code>code</code> but close the connection the same time this endpoint does do but with an other <code>code</code>. <br>
 **/
public synchronized void closeConnection( int code, String message, boolean remote ) {
	if( getReadyState() == READYSTATE.CLOSED ) {
		return;
	}

	if( key != null ) {
		// key.attach( null ); //see issue #114
		key.cancel();
	}
	if( channel != null ) {
		try {
			channel.close();
		} catch ( IOException e ) {
			if( e.getMessage().equals( "Broken pipe" ) ) {
				if( WebSocketImpl.DEBUG ) {
					System.out.println( "Caught IOException: Broken pipe during closeConnection()" );
				}
			} else {
				wsl.onWebsocketError( this, e );
			}
		}
	}
	try {
		this.wsl.onWebsocketClose( this, code, message, remote );
	} catch ( RuntimeException e ) {
		wsl.onWebsocketError( this, e );
	}
	if( draft != null )
		draft.reset();
	handshakerequest = null;

	setReadyState(READYSTATE.CLOSED);
}

public static Document parse(String html) {
    return Parser.parse(html, "");
}

final void newAttribute() {
    if (attributes == null)
        attributes = new Attributes();

    if (hasAttrName && attributes.size() < MaxAttributes) {
        // the tokeniser has skipped whitespace control chars, but trimming could collapse to empty for other control codes, so verify here
        String name = attrName.length() > 0 ? attrName.toString() : attrNameS;
        name = name.trim();
        if (name.length() > 0) {
            String value;
            if (hasAttrValue)
                value = attrValue.length() > 0 ? attrValue.toString() : attrValueS;
            else if (hasEmptyAttrValue)
                value = "";
            else
                value = null;
            // note that we add, not put. So that the first is kept, and rest are deduped, once in a context where case sensitivity is known (the appropriate tree builder).
            attributes.add(name, value);
        }
    }
    reset(attrName);
    attrNameS = null;
    hasAttrName = false;

    reset(attrValue);
    attrValueS = null;
    hasAttrValue = false;
    hasEmptyAttrValue = false;
}

/**
 * Returns whether the handshake phase has is completed.
 * In case of a broken handshake this will be never the case.
 **/
private boolean decodeHandshake( ByteBuffer socketBufferNew ) {
	ByteBuffer socketBuffer;
	if( tmpHandshakeBytes.capacity() == 0 ) {
		socketBuffer = socketBufferNew;
	} else {
		if( tmpHandshakeBytes.remaining() < socketBufferNew.remaining() ) {
			ByteBuffer buf = ByteBuffer.allocate( tmpHandshakeBytes.capacity() + socketBufferNew.remaining() );
			tmpHandshakeBytes.flip();
			buf.put( tmpHandshakeBytes );
			tmpHandshakeBytes = buf;
		}

		tmpHandshakeBytes.put( socketBufferNew );
		tmpHandshakeBytes.flip();
		socketBuffer = tmpHandshakeBytes;
	}
	socketBuffer.mark();
	try {
		if( draft == null ) {
			HandshakeState isflashedgecase = isFlashEdgeCase( socketBuffer );
			if( isflashedgecase == HandshakeState.MATCHED ) {
				try {
					write( Collections.singletonList( ByteBuffer.wrap(Charsetfunctions.utf8Bytes(wsl.getFlashPolicy(this)))));
					close(CloseFrame.FLASHPOLICY, "");
				} catch ( InvalidDataException e ) {
					close( CloseFrame.ABNORMAL_CLOSE, "remote peer closed connection before flashpolicy could be transmitted", true );
				}
				return false;
			}
		}
		HandshakeState handshakestate;

		try {
			if( role == Role.SERVER ) {
				if( draft == null ) {
					for( Draft d : knownDrafts ) {
						d = d.copyInstance();
						try {
							d.setParseMode( role );
							socketBuffer.reset();
							Handshakedata tmphandshake = d.translateHandshake( socketBuffer );
							if( !( tmphandshake instanceof ClientHandshake ) ) {
								closeConnectionDueToWrongHandshake( new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "wrong http function" ));
								return false;
							}
							ClientHandshake handshake = ( ClientHandshake ) tmphandshake;
							handshakestate = d.acceptHandshakeAsServer( handshake );
							if( handshakestate == HandshakeState.MATCHED ) {
								resourceDescriptor = handshake.getResourceDescriptor();
								ServerHandshakeBuilder response;
								try {
									response = wsl.onWebsocketHandshakeReceivedAsServer( this, d, handshake );
								} catch ( InvalidDataException e ) {
									closeConnectionDueToWrongHandshake( e );
									return false;
								} catch ( RuntimeException e ) {
									wsl.onWebsocketError( this, e );
									closeConnectionDueToInternalServerError( e );
									return false;
								}
								write( d.createHandshake( d.postProcessHandshakeResponseAsServer( handshake, response ), role ) );
								draft = d;
								open( handshake );
								return true;
							}
						} catch ( InvalidHandshakeException e ) {
							// go on with an other draft
						}
					}
					if( draft == null ) {
						closeConnectionDueToWrongHandshake( new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "no draft matches"));
					}
					return false;
				} else {
					// special case for multiple step handshakes
					Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
					if( !( tmphandshake instanceof ClientHandshake ) ) {
						flushAndClose( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
						return false;
					}
					ClientHandshake handshake = ( ClientHandshake ) tmphandshake;
					handshakestate = draft.acceptHandshakeAsServer( handshake );

					if( handshakestate == HandshakeState.MATCHED ) {
						open( handshake );
						return true;
					} else {
						close( CloseFrame.PROTOCOL_ERROR, "the handshake did finaly not match" );
					}
					return false;
				}
			} else if( role == Role.CLIENT ) {
				draft.setParseMode( role );
				Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
				if( !( tmphandshake instanceof ServerHandshake ) ) {
					flushAndClose( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
					return false;
				}
				ServerHandshake handshake = ( ServerHandshake ) tmphandshake;
				handshakestate = draft.acceptHandshakeAsClient( handshakerequest, handshake );
				if( handshakestate == HandshakeState.MATCHED ) {
					try {
						wsl.onWebsocketHandshakeReceivedAsClient( this, handshakerequest, handshake );
					} catch ( InvalidDataException e ) {
						flushAndClose( e.getCloseCode(), e.getMessage(), false );
						return false;
					} catch ( RuntimeException e ) {
						wsl.onWebsocketError( this, e );
						flushAndClose( CloseFrame.NEVER_CONNECTED, e.getMessage(), false );
						return false;
					}
					open( handshake );
					return true;
				} else {
					close( CloseFrame.PROTOCOL_ERROR, "draft " + draft + " refuses handshake" );
				}
			}
		} catch ( InvalidHandshakeException e ) {
			close( e );
		}
	} catch ( IncompleteHandshakeException e ) {
		if( tmpHandshakeBytes.capacity() == 0 ) {
			socketBuffer.reset();
			int newsize = e.getPreferedSize();
			if( newsize == 0 ) {
				newsize = socketBuffer.capacity() + 16;
			} else {
				assert ( e.getPreferedSize() >= socketBuffer.remaining() );
			}
			tmpHandshakeBytes = ByteBuffer.allocate( newsize );

			tmpHandshakeBytes.put( socketBufferNew );
			// tmpHandshakeBytes.flip();
		} else {
			tmpHandshakeBytes.position( tmpHandshakeBytes.limit() );
			tmpHandshakeBytes.limit( tmpHandshakeBytes.capacity() );
		}
	}
	return false;
}

protected boolean isDataAttribute() {
    return key.startsWith(Attributes.dataPrefix) && key.length() > Attributes.dataPrefix.length();
}

public void close( int code, String message, boolean remote ) {
	if( readystate != READYSTATE.CLOSING && readystate != READYSTATE.CLOSED ) {
		if( readystate == READYSTATE.OPEN ) {
			if( code == CloseFrame.ABNORMAL_CLOSE ) {
				assert ( !remote );
				readystate = READYSTATE.CLOSING;
				flushAndClose( code, message, false );
				return;
			}
			if( draft.getCloseHandshakeType() != CloseHandshakeType.NONE ) {
				try {
					if( !remote ) {
						try {
							wsl.onWebsocketCloseInitiated( this, code, message );
						} catch ( RuntimeException e ) {
							wsl.onWebsocketError( this, e );
						}
					}
					CloseFrame closeFrame = new CloseFrame();
					closeFrame.setReason( message );
					closeFrame.setCode( code );
					closeFrame.isValid();
					sendFrame( closeFrame );
				} catch ( InvalidDataException e ) {
					wsl.onWebsocketError( this, e );
					flushAndClose( CloseFrame.ABNORMAL_CLOSE, "generated frame is invalid", false );
				}
			}
			flushAndClose( code, message, remote );
		} else if( code == CloseFrame.FLASHPOLICY ) {
			assert ( remote );
			flushAndClose( CloseFrame.FLASHPOLICY, message, true );
		} else if( code == CloseFrame.PROTOCOL_ERROR ) { // this endpoint found a PROTOCOL_ERROR
			flushAndClose( code, message, remote );
		} else {
			flushAndClose( CloseFrame.NEVER_CONNECTED, message, false );
		}
		readystate = READYSTATE.CLOSING;
		tmpHandshakeBytes = null;
		return;
	}
}

private void matchesWholeText(boolean own) {
    String query = own ? ":matchesWholeOwnText" : ":matchesWholeText";
    tq.consume(query);
    String regex = tq.chompBalanced('(', ')'); // don't unescape, as regex bits will be escaped
    Validate.notEmpty(regex, query + "(regex) query must not be empty");

    evals.add(own
        ? new Evaluator.MatchesWholeOwnText(Pattern.compile(regex))
        : new Evaluator.MatchesWholeText(Pattern.compile(regex)));
}

