private Elements select() {
    tq.consumeWhitespace();
    addElements(findElements()); // chomp first matcher off queue        
    while (!tq.isEmpty()) {
        // hierarchy and extras (todo: implement +, ~)
        boolean seenWhite = tq.consumeWhitespace();

        if (tq.matchChomp(",")) { // group or
            while (!tq.isEmpty()) {
                String subQuery = tq.chompTo(",");
                elements.addAll(select(subQuery, root));
            }
        } else if (tq.matchesAny(combinators)) {
            combinator(tq.consume().toString());
        } else if (seenWhite) {
            combinator(" ");
        } else { // E.class, E#id, E[attr] etc. AND
            Elements candidates = findElements(); // take next el, #. etc off queue
            intersectElements(filterForSelf(elements, candidates));
        }
    }
    return new Elements(elements);
}

/**
 * @return True if all data has been sent to the client, false if there
 *    is still some buffered.
 */
boolean handleWrite() throws IOException {
  synchronized (this.bufferQueueMutex) {
    ByteBuffer buffer = this.bufferQueue.peek();
    while (buffer != null) {
      channelWrite( buffer );
      if (buffer.remaining() > 0) {
        return false; // Didn't finish this buffer.  There's more to send.
      } else {
        this.bufferQueue.poll();  // Buffer finished.  Remove it.
        buffer = this.bufferQueue.peek();
      }
    }
    return true;
  }
}

public static String normaliseWhitespace(String string) {
    StringBuilder sb = new StringBuilder(string.length());

    boolean lastWasWhite = false;
    boolean modified = false;

    int l = string.length();
    int c;
    for (int i = 0; i < l; i+= Character.charCount(c)) {
        c = string.codePointAt(i);
        if (isWhitespace(c)) {
            if (lastWasWhite) {
                modified = true;
                continue;
            }
            if (c != ' ')
                modified = true;
            sb.append(' ');
            lastWasWhite = true;
        }
        else {
            sb.appendCodePoint(c);
            lastWasWhite = false;
        }
    }
    return modified ? sb.toString() : string;
}

public void run() {
	if (!doEnsureSingleThread()) {
		return;
	}
	if (!doSetupSelectorAndServerThread()) {
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						continue;
					}

					if( key.isAcceptable() ) {
						doAccept(key, i);
						continue;
					}

					if( key.isReadable() ) {
						if (!doRead(key, i)) {
							continue;
						}
					}

					if( key.isWritable() ) {
						doWrite(key);
					}
				}
				doAdditionalRead();
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				// FIXME controlled shutdown (e.g. take care of buffermanagement)
				return;
			}
		}
	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		doServerShutdown();
	}
}

private boolean inBodyEndTag(Token t, HtmlTreeBuilder tb) {
    final Token.EndTag endTag = t.asEndTag();
    final String name = endTag.normalName();

    switch (name) {
        case "sarcasm": // *sigh*
        case "span":
            // same as final fall through, but saves short circuit
            return anyOtherEndTag(t, tb);
        case "li":
            if (!tb.inListItemScope(name)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(name);
            }
            break;
        case "body":
            if (!tb.inScope("body")) {
                tb.error(this);
                return false;
            } else {
                // todo: error if stack contains something not dd, dt, li, optgroup, option, p, rp, rt, tbody, td, tfoot, th, thead, tr, body, html
                tb.transition(AfterBody);
            }
            break;
        case "html":
            boolean notIgnored = tb.processEndTag("body");
            if (notIgnored)
                return tb.process(endTag);
            break;
        case "form":
            Element currentForm = tb.getFormElement();
            tb.setFormElement(null);
            if (currentForm == null || !tb.inScope(name)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags();
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                // remove currentForm from stack. will shift anything under up.
                tb.removeFromStack(currentForm);
            }
            break;
        case "p":
            if (!tb.inButtonScope(name)) {
                tb.error(this);
                tb.processStartTag(name); // if no p to close, creates an empty <p></p>
                return tb.process(endTag);
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(name);
            }
            break;
        case "dd":
        case "dt":
            if (!tb.inScope(name)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(name);
            }
            break;
        case "h1":
        case "h2":
        case "h3":
        case "h4":
        case "h5":
        case "h6":
            if (!tb.inScope(Constants.Headings)) {
                tb.error(this);
                return false;
            } else {
                tb.generateImpliedEndTags(name);
                if (!tb.currentElement().normalName().equals(name))
                    tb.error(this);
                tb.popStackToClose(Constants.Headings);
            }
            break;
        case "br":
            tb.error(this);
            tb.processStartTag("br");
            return false;
        default:
            // todo - move rest to switch if desired
            if (StringUtil.inSorted(name, Constants.InBodyEndAdoptionFormatters)) {
                return inBodyEndTagAdoption(t, tb);
            } else if (StringUtil.inSorted(name, Constants.InBodyEndClosers)) {
                if (!tb.inScope(name)) {
                    // nothing to close
                    tb.error(this);
                    return false;
                } else {
                    tb.generateImpliedEndTags();
                    if (!tb.currentElement().normalName().equals(name))
                        tb.error(this);
                    tb.popStackToClose(name);
                }
            } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                if (!tb.inScope("name")) {
                    if (!tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    }
                    tb.generateImpliedEndTags();
                    if (!tb.currentElement().normalName().equals(name))
                        tb.error(this);
                    tb.popStackToClose(name);
                    tb.clearFormattingElementsToLastMarker();
                }
            } else {
                return anyOtherEndTag(t, tb);
            }
    }
    return true;
}

protected void addChildren(int index, Node... children) {
    Validate.noNullElements(children);
    for (int i = children.length - 1; i >= 0; i--) {
        Node in = children[i];
        if (in.parentNode != null)
            in.parentNode.removeChild(in);

        childNodes.add(index, in);
        in.setParentNode(this);
    }
    reindexChildren();
}

