public WebSocketServer( InetSocketAddress address , int decodercount , List<Draft> drafts ) {
	if( drafts == null )
		this.drafts = Collections.emptyList();
	else
		this.drafts = drafts;
	setAddress( address );

	oqueue = new LinkedBlockingQueue<WebSocketImpl>();
	iqueue = new LinkedList<WebSocketImpl>();

	decoders = new ArrayList<WebSocketWorker>( decodercount );
	buffers = new LinkedBlockingQueue<ByteBuffer>();
	for( int i = 0 ; i < decodercount ; i++ ) {
		WebSocketWorker ex = new WebSocketWorker();
		decoders.add( ex );
		ex.start();
	}
}

public void close( int code, String message, boolean remote ) {
	if( readystate != READYSTATE.CLOSING && readystate != READYSTATE.CLOSED ) {
		if( readystate == READYSTATE.OPEN ) {
			if( code == CloseFrame.ABNORMAL_CLOSE ) {
				assert ( !remote );
				readystate = READYSTATE.CLOSING;
				flushAndClose( code, message, false );
				return;
			}
			if( draft.getCloseHandshakeType() != CloseHandshakeType.NONE ) {
				try {
					if( !remote ) {
						try {
							wsl.onWebsocketCloseInitiated( this, code, message );
						} catch ( RuntimeException e ) {
							wsl.onWebsocketError( this, e );
						}
					}
					CloseFrame closeFrame = new CloseFrame();
					closeFrame.setReason( message );
					closeFrame.setCode( code );
					closeFrame.isValid();
					sendFrame( closeFrame );
				} catch ( InvalidDataException e ) {
					wsl.onWebsocketError( this, e );
					flushAndClose( CloseFrame.ABNORMAL_CLOSE, "generated frame is invalid", false );
				}
			}
			flushAndClose( code, message, remote );
		} else if( code == CloseFrame.FLASHPOLICY ) {
			assert ( remote );
			flushAndClose( CloseFrame.FLASHPOLICY, message, true );
		} else if( code == CloseFrame.PROTOCOL_ERROR ) { // this endpoint found a PROTOCOL_ERROR
			flushAndClose( code, message, remote );
		} else {
			flushAndClose( CloseFrame.NEVER_CONNECTED, message, false );
		}
		readystate = READYSTATE.CLOSING;
		tmpHandshakeBytes = null;
		return;
	}
}

boolean process(Token t, HtmlTreeBuilder tb) {
    switch (t.type) {
        case Character: {
            Token.Character c = t.asCharacter();
            if (c.getData().equals(nullString)) {
                // todo confirm that check
                tb.error(this);
                return false;
            } else if (tb.framesetOk() && isWhitespace(c)) { // don't check if whitespace if frames already closed
                tb.reconstructFormattingElements();
                tb.insert(c);
            } else {
                tb.reconstructFormattingElements();
                tb.insert(c);
                tb.framesetOk(false);
            }
            break;
        }
        case Comment: {
            tb.insert(t.asComment());
            break;
        }
        case Doctype: {
            tb.error(this);
            return false;
        }
        case StartTag:
            return inBodyStartTag(t, tb);
        case EndTag:
            return inBodyEndTag(t, tb);
        case EOF:
            // todo: error if stack contains something not dd, dt, li, p, tbody, td, tfoot, th, thead, tr, body, html
            // stop parsing
            break;
    }
    return true;
}

/**
 * Constructor for the websocket protocol specified by RFC 6455 with custom extensions
 *
 * @param inputExtensions the extensions which should be used for this draft
 */
public Draft_6455( List<IExtension> inputExtensions ) {
	knownExtensions = new ArrayList<IExtension>();
	boolean hasDefault = false;
	byteBufferList = new ArrayList<ByteBuffer>();
	for( IExtension inputExtension : inputExtensions ) {
		if( inputExtension.getClass().equals( DefaultExtension.class ) ) {
			hasDefault = true;
		}
	}
	knownExtensions.addAll( inputExtensions );
	//We always add the DefaultExtension to implement the normal RFC 6455 specification
	if( !hasDefault ) {
		knownExtensions.add( this.knownExtensions.size(), extension );
	}
}

