public void run() {
	synchronized ( this ) {
		if( selectorthread != null )
			throw new IllegalStateException( getClass().getName() + " can only be started once." );
		selectorthread = Thread.currentThread();
		if( isclosed.get() ) {
			return;
		}
	}
	selectorthread.setName( "WebSocketSelector-" + selectorthread.getId() );
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		ServerSocket socket = server.socket();
		socket.setReceiveBufferSize( WebSocketImpl.RCVBUF );
		socket.setReuseAddress( isReuseAddr() );
		socket.bind( address );
		selector = Selector.open();
		server.register( selector, server.validOps() );
		startConnectionLostTimer();
		onStart();
	} catch ( IOException ex ) {
		handleFatal( null, ex );
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						// Object o = key.attachment();
						continue;
					}

					if( key.isAcceptable() ) {
						if( !onConnect( key ) ) {
							key.cancel();
							continue;
						}

						SocketChannel channel = server.accept();
						if(channel==null){
							continue;
						}
						channel.configureBlocking( false );
						Socket socket = channel.socket();
						socket.setTcpNoDelay( isTcpNoDelay() );
						socket.setKeepAlive( true );
						WebSocketImpl w = wsf.createWebSocket( this, drafts );
						w.setSelectionKey(channel.register( selector, SelectionKey.OP_READ, w ));
						try {
							w.channel = wsf.wrapChannel( channel, w.getSelectionKey() );
							i.remove();
							allocateBuffers( w );
							continue;
						} catch (IOException ex) {
							if( w.getSelectionKey() != null )
								w.getSelectionKey().cancel();

							handleIOException( w.getSelectionKey(), null, ex );
						}
						continue;
					}

					if( key.isReadable() ) {
						conn = (WebSocketImpl) key.attachment();
						ByteBuffer buf = takeBuffer();
						if(conn.channel == null){
							if( key != null )
								key.cancel();

							handleIOException( key, conn, new IOException() );
							continue;
						}
						try {
							if( SocketChannelIOHelper.read( buf, conn, conn.channel ) ) {
								if( buf.hasRemaining() ) {
									conn.inQueue.put( buf );
									queue( conn );
									i.remove();
									if( conn.channel instanceof WrappedByteChannel ) {
										if( ( (WrappedByteChannel) conn.channel ).isNeedRead() ) {
											iqueue.add( conn );
										}
									}
								} else
									pushBuffer( buf );
							} else {
								pushBuffer( buf );
							}
						} catch ( IOException e ) {
							pushBuffer( buf );
							throw e;
						}
					}
					if( key.isWritable() ) {
						conn = (WebSocketImpl) key.attachment();
						if( SocketChannelIOHelper.batch( conn, conn.channel ) ) {
							if( key.isValid() )
								key.interestOps( SelectionKey.OP_READ );
						}
					}
				}
				while ( !iqueue.isEmpty() ) {
					conn = iqueue.remove( 0 );
					WrappedByteChannel c = ( (WrappedByteChannel) conn.channel );
					ByteBuffer buf = takeBuffer();
					try {
						if( SocketChannelIOHelper.readMore( buf, conn, c ) )
							iqueue.add( conn );
						if( buf.hasRemaining() ) {
							conn.inQueue.put( buf );
							queue( conn );
						} else {
							pushBuffer( buf );
						}
					} catch ( IOException e ) {
						pushBuffer( buf );
						throw e;
					}

				}
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				return;// FIXME controlled shutdown (e.g. take care of buffermanagement)
			}
		}

	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		stopConnectionLostTimer();
		if( decoders != null ) {
			for( WebSocketWorker w : decoders ) {
				w.interrupt();
			}
		}
		if( selector != null ) {
			try {
				selector.close();
			} catch ( IOException e ) {
				log.error( "IOException during selector.close", e );
				onError( null, e );
			}
		}
		if( server != null ) {
			try {
				server.close();
			} catch ( IOException e ) {
				log.error( "IOException during server.close", e );
				onError( null, e );
			}
		}
	}
}

static void escape(Appendable accum, String string, Document.OutputSettings out,
                   boolean inAttribute, boolean normaliseWhite, boolean stripLeadingWhite) throws IOException {

    boolean lastWasWhite = false;
    boolean reachedNonWhite = false;
    final EscapeMode escapeMode = out.escapeMode();
    final CharsetEncoder encoder = out.encoder();
    final CoreCharset coreCharset = CoreCharset.byName(encoder.charset().name());
    final int length = string.length();

    int codePoint;
    for (int offset = 0; offset < length; offset += Character.charCount(codePoint)) {
        codePoint = string.codePointAt(offset);

        if (normaliseWhite) {
            if (StringUtil.isWhitespace(codePoint)) {
                if ((stripLeadingWhite && !reachedNonWhite) || lastWasWhite)
                    continue;
                accum.append(' ');
                lastWasWhite = true;
                continue;
            } else {
                lastWasWhite = false;
                reachedNonWhite = true;
            }
        }
        // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
        if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
            final char c = (char) codePoint;
            // html specific and required escapes:
            switch (c) {
                case '&':
                    accum.append("&amp;");
                    break;
                case 0xA0:
                    if (escapeMode != EscapeMode.xhtml)
                        accum.append("&nbsp;");
                    else
                        accum.append("&#xa0;");
                    break;
                case '<':
                    // escape when in character data or when in a xml attribue val; not needed in html attr val
                    if (!inAttribute || escapeMode == EscapeMode.xhtml)
                        accum.append("&lt;");
                    else
                        accum.append(c);
                    break;
                case '>':
                    if (!inAttribute)
                        accum.append("&gt;");
                    else
                        accum.append(c);
                    break;
                case '"':
                    if (inAttribute)
                        accum.append("&quot;");
                    else
                        accum.append(c);
                    break;
                default:
                    if (canEncode(coreCharset, c, encoder))
                        accum.append(c);
                    else
                        appendEncoded(accum, escapeMode, codePoint);
            }
        } else {
            final String c = new String(Character.toChars(codePoint));
            if (encoder.canEncode(c)) // uses fallback encoder for simplicity
                accum.append(c);
            else
                appendEncoded(accum, escapeMode, codePoint);
        }
    }
}

public void run() {
  try {
    server = ServerSocketChannel.open();
    server.configureBlocking(false);
    server.socket().bind(new java.net.InetSocketAddress(port));

    selector = Selector.open();
    server.register(selector, server.validOps());
  } catch (IOException ex) {
    ex.printStackTrace();
    return;
  }

  while(true) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while(i.hasNext()) {
        SelectionKey key = i.next();

        // Remove the current key
        i.remove();

        // if isAcceptable == true
        // then a client required a connection
        if (key.isAcceptable()) {
          SocketChannel client = server.accept();
          client.configureBlocking(false);
          WebSocket c = new WebSocket(client, new LinkedBlockingQueue<ByteBuffer>(), this);
          client.register(selector, SelectionKey.OP_READ, c);
        }

        // if isReadable == true
        // then the server is ready to read
        if (key.isReadable()) {
          WebSocket conn = (WebSocket)key.attachment();
          conn.handleRead();
        }

        // if isWritable == true
        // then we need to send the rest of the data to the client
        if (key.isValid() && key.isWritable()) {
          WebSocket conn = (WebSocket)key.attachment();
          if (conn.handleWrite()) {
            conn.socketChannel().register(selector,
                SelectionKey.OP_READ, conn);
          }
        }
      }

      for (WebSocket conn : this.connections) {
        // We have to do this check here, and not in the thread that
        // adds the buffered data to the WebSocket, because the
        // Selector is not thread-safe, and can only be accessed
        // by this thread.
        if (conn.hasBufferedData()) {
          conn.socketChannel().register(selector,
              SelectionKey.OP_READ | SelectionKey.OP_WRITE, conn);
        }
      }
    } catch (IOException ex) {
      ex.printStackTrace();
    } catch (RuntimeException ex) {
      ex.printStackTrace();
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketServer thread ended!");
}

public void run() {
  int port = uri.getPort();
  if (port == -1) {
    port = WebSocket.DEFAULT_PORT;
  }

  // The WebSocket constructor expects a SocketChannel that is
  // non-blocking, and has a Selector attached to it.
  try {
    client = SocketChannel.open();
    client.configureBlocking(false);
    client.connect(new InetSocketAddress(uri.getHost(), port));

    selector = Selector.open();

    this.conn = new WebSocket(client, new LinkedBlockingQueue<ByteBuffer>(), this);
    // At first, we're only interested in the 'CONNECT' keys.
    client.register(selector, SelectionKey.OP_CONNECT);

  } catch (IOException ex) {
    ex.printStackTrace();
    return;
  }

  // Continuous loop that is only supposed to end when "close" is called.
  while (this.running) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while (i.hasNext()) {
        SelectionKey key = i.next();
        i.remove();

        // When 'conn' has connected to the host
        if (key.isConnectable()) {

          // Ensure connection is finished
          if (client.isConnectionPending()) {
            client.finishConnect();
          }

          // Now that we're connected, re-register for only 'READ' keys.
          client.register(selector, SelectionKey.OP_READ);

          // Now send the WebSocket client-side handshake
          String path = uri.getPath();
          if (path.indexOf("/") != 0) {
            path = "/" + path;
          }
          String host = uri.getHost() + (port != WebSocket.DEFAULT_PORT ? ":" + port : "");
          String origin = null; // TODO: Make 'origin' configurable
          String request = "GET " + path + " HTTP/1.1\r\n" +
                            "Upgrade: WebSocket\r\n" +
                            "Connection: Upgrade\r\n" +
                            "Host: " + host + "\r\n" +
                            "Origin: " + origin + "\r\n";
          if (this.draft == WebSocketDraft.DRAFT76) {
            request += "Sec-WebSocket-Key1: " + this.generateKey() + "\r\n";
            request += "Sec-WebSocket-Key2: " + this.generateKey() + "\r\n";
            this.key3 = new byte[8];
            (new Random()).nextBytes(this.key3);
          }
          //extraHeaders.toString() +
          request+="\r\n";
          conn.socketChannel().write(ByteBuffer.wrap(request.getBytes(WebSocket.UTF8_CHARSET)));
          if (this.key3 != null) {
            conn.socketChannel().write(ByteBuffer.wrap(this.key3));
          }
        }

        // When 'conn' has recieved some data
        if (key.isReadable()) {
          conn.handleRead();
        }
      }
    } catch (IOException ex) {
      ex.printStackTrace();
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketClient thread ended!");
}

/**
 * Get a CSS selector that will uniquely select this element.
 * <p>
 * If the element has an ID, returns #id;
 * otherwise returns the parent (if any) CSS selector, followed by {@literal '>'},
 * followed by a unique selector for the element (tag.class.class:nth-child(n)).
 * </p>
 *
 * @return the CSS Path that can be used to retrieve the element in a selector.
 */
public String cssSelector() {
    if (id().length() > 0) {
        // prefer to return the ID - but check that it's actually unique first!
        String idSel = "#" + escapeCssIdentifier(id());
        Document doc = ownerDocument();
        if (doc != null) {
            Elements els = doc.select(idSel);
            if (els.size() == 1 && els.get(0) == this) // otherwise, continue to the nth-child impl
                return idSel;
        } else {
            return idSel; // no ownerdoc, return the ID selector
        }
    }

    StringBuilder selector = StringUtil.borrowBuilder();
    Element el = this;
    while (el != null && !(el instanceof Document)) {
        selector.insert(0, el.cssSelectorComponent());
        el = el.parent();
    }
    return StringUtil.releaseBuilder(selector);
}

/**
 * This method will do whatever necessary to process the sslengine handshake.
 * Thats why it's called both from the {@link #read(ByteBuffer)} and {@link #write(ByteBuffer)}
 **/
private synchronized void processHandshake() throws IOException {
	if( sslEngine.getHandshakeStatus() == HandshakeStatus.NOT_HANDSHAKING )
		return; // since this may be called either from a reading or a writing thread and because this method is synchronized it is necessary to double check if we are still handshaking.
	if( !tasks.isEmpty() ) {
		Iterator<Future<?>> it = tasks.iterator();
		while ( it.hasNext() ) {
			Future<?> f = it.next();
			if( f.isDone() ) {
				it.remove();
			} else {
				if( isBlocking() )
					consumeFutureUninterruptible( f );
				return;
			}
		}
	}

	if( sslEngine.getHandshakeStatus() == SSLEngineResult.HandshakeStatus.NEED_UNWRAP ) {
		if( !isBlocking() || readEngineResult.getStatus() == Status.BUFFER_UNDERFLOW ) {
			inCrypt.compact();
			int read = socketChannel.read( inCrypt );
			if( read == -1 ) {
				throw new IOException( "connection closed unexpectedly by peer" );
			}
			inCrypt.flip();
		}
		inData.compact();
		unwrap();
		if( readEngineResult.getHandshakeStatus() == HandshakeStatus.FINISHED ) {
			createBuffers( sslEngine.getSession() );
			return;
		}
	}
	consumeDelegatedTasks();
	if( tasks.isEmpty() || sslEngine.getHandshakeStatus() == SSLEngineResult.HandshakeStatus.NEED_WRAP ) {
		socketChannel.write( wrap( emptybuffer ) );
		if( writeEngineResult.getHandshakeStatus() == HandshakeStatus.FINISHED ) {
			createBuffers( sslEngine.getSession() );
			return;
		}
	}
	assert ( sslEngine.getHandshakeStatus() != HandshakeStatus.NOT_HANDSHAKING );// this function could only leave NOT_HANDSHAKING after createBuffers was called unless #190 occurs which means that nio wrap/unwrap never return HandshakeStatus.FINISHED

	bufferallocations = 1; // look at variable declaration why this line exists and #190. Without this line buffers would not be be recreated when #190 AND a rehandshake occur.
}

