@Override
public void run() {
	Thread.currentThread().setName( "WebSocketWriteThread-" + Thread.currentThread().getId() );
	try {
		try {
			while( !Thread.interrupted() ) {
				ByteBuffer buffer = engine.outQueue.take();
				ostream.write( buffer.array(), 0, buffer.limit() );
				ostream.flush();
			}
		} catch ( InterruptedException e ) {
			for (ByteBuffer buffer : engine.outQueue) {
				ostream.write( buffer.array(), 0, buffer.limit() );
				ostream.flush();
			}
			Thread.currentThread().interrupt();
		}
	} catch ( IOException e ) {
		handleIOException( e );
	} finally {
		closeSocket();
		writeThread = null;
	}
}

private Elements select() {
    tq.consumeWhitespace();
    addElements(findElements()); // chomp first matcher off queue        
    while (!tq.isEmpty()) {
        // hierarchy and extras (todo: implement +, ~)
        boolean seenWhite = tq.consumeWhitespace();

        if (tq.matchChomp(",")) { // group or
            while (!tq.isEmpty()) {
                String subQuery = tq.chompTo(",");
                elements.addAll(select(subQuery, root));
            }
        } else if (tq.matchChomp(">")) { // parent > child
            String subQuery = tq.chompTo(">"); // support multi > childs
            Elements candidates = select(subQuery, elements);
            Elements children = filterForChildren(elements, candidates);
            elements.clear(); elements.addAll(children);
        } else if (seenWhite) { // ancestor descendant
            Elements candidates = select(tq.remainder(), elements);
            return filterForDescendants(elements, candidates);
        } else { // E.class, E#id, E[attr] etc. AND
            Elements candidates = findElements(); // take next el, #. etc off queue
            intersectElements(filterForSelf(elements, candidates));
        }
    }
    return new Elements(elements);
}

public Document parse() {
    // TODO: figure out implicit head & body elements
    Document doc = new Document();
    stack.add(doc);

    StringBuilder commentAccum = null;

    while (tokenStream.hasNext()) {
        Token token = tokenStream.next();

        if (token.isFullComment()) { // <!-- comment -->
            Comment comment = new Comment(token.getCommentData());
            stack.getLast().addChild(comment);
        } else if (token.isStartComment()) { // <!-- comment
            commentAccum = new StringBuilder(token.getCommentData());
        } else if (token.isEndComment() && commentAccum != null) { // comment -->
            commentAccum.append(token.getCommentData());
            Comment comment = new Comment(commentAccum.toString());
            stack.getLast().addChild(comment);
            commentAccum = null;
        } else if (commentAccum != null) { // within a comment
            commentAccum.append(token.getData());
        }

        else if (token.isStartTag()) {
            Attributes attributes = attributeParser.parse(token.getAttributeString());
            Tag tag = Tag.valueOf(token.getTagName());
            StartTag startTag = new StartTag(tag, attributes);

            // if tag is "html", we already have it, so OK to ignore skip. todo: abstract this. and can there be attributes to set?
            if (doc.getTag().equals(tag)) continue;

            Element parent = popStackToSuitableContainer(tag);
            Validate.notNull(parent, "Should always have a viable container");
            Element node = new Element(startTag);
            parent.addChild(node);
            stack.add(node);
        }

        if (token.isEndTag() && commentAccum == null) { // empty tags are both start and end tags
            stack.removeLast();
        }



        // TODO[must] handle comments

        else if (token.isTextNode()) {
            String text = token.getData();
            TextNode textNode = new TextNode(text);
            stack.getLast().addChild(textNode);
        }
    }
    return doc;
}

public void close( int code, String message, boolean remote ) {
	if( getReadyState()  != READYSTATE.CLOSING && readystate != READYSTATE.CLOSED ) {
		if( getReadyState()  == READYSTATE.OPEN ) {
			if( code == CloseFrame.ABNORMAL_CLOSE ) {
				assert ( !remote );
				setReadyState(READYSTATE.CLOSING);
				flushAndClose( code, message, false );
				return;
			}
			if( draft.getCloseHandshakeType() != CloseHandshakeType.NONE ) {
				try {
					if( !remote ) {
						try {
							wsl.onWebsocketCloseInitiated( this, code, message );
						} catch ( RuntimeException e ) {
							wsl.onWebsocketError( this, e );
						}
					}
					CloseFrame closeFrame = new CloseFrame();
					closeFrame.setReason( message );
					closeFrame.setCode( code );
					closeFrame.isValid();
					sendFrame( closeFrame );
				} catch ( InvalidDataException e ) {
					wsl.onWebsocketError( this, e );
					flushAndClose( CloseFrame.ABNORMAL_CLOSE, "generated frame is invalid", false );
				}
			}
			flushAndClose( code, message, remote );
		} else if( code == CloseFrame.FLASHPOLICY ) {
			assert ( remote );
			flushAndClose( CloseFrame.FLASHPOLICY, message, true );
		} else if( code == CloseFrame.PROTOCOL_ERROR ) { // this endpoint found a PROTOCOL_ERROR
			flushAndClose( code, message, remote );
		} else {
			flushAndClose( CloseFrame.NEVER_CONNECTED, message, false );
		}
		setReadyState(READYSTATE.CLOSING);
		tmpHandshakeBytes = null;
		return;
	}
}

