protected List<Framedata> translateRegularFrame( ByteBuffer buffer ) throws InvalidDataException {
	while ( buffer.hasRemaining() ) {
		byte newestByte = buffer.get();
		if( newestByte == START_OF_FRAME ) { // Beginning of Frame
			if( readingState )
				return null;
			readingState = true;
		} else if( newestByte == END_OF_FRAME ) { // End of Frame
			if( !readingState )
				return null;
			// currentFrame will be null if END_OF_FRAME was send directly after
			// START_OF_FRAME, thus we will send 'null' as the sent message.
			if( this.currentFrame != null ) {
				currentFrame.flip();
				FramedataImpl1 curframe = new FramedataImpl1();
				curframe.setPayload( currentFrame );
				curframe.setFin( true );
				curframe.setOptcode( inframe ? Opcode.CONTINIOUS : Opcode.TEXT );
				readyframes.add( curframe );
				this.currentFrame = null;
				buffer.mark();
			}
			readingState = false;
			inframe = false;
		} else if( readingState ) { // Regular frame data, add to current frame buffer //TODO This code is very expensive and slow
			if( currentFrame == null ) {
				currentFrame = createBuffer();
			} else if( !currentFrame.hasRemaining() ) {
				currentFrame = increaseBuffer( currentFrame );
			}
			currentFrame.put( newestByte );
		} else {
			return null;
		}
	}
	if( readingState ) {
		FramedataImpl1 curframe = new FramedataImpl1();
		curframe.setPayload( currentFrame );
		curframe.setFin( false );
		curframe.setOptcode( inframe ? Opcode.CONTINIOUS : Opcode.TEXT );
		inframe = true;
		readyframes.add( curframe );
	}

	List<Framedata> frames = readyframes;
	readyframes = new LinkedList<Framedata>();
	this.currentFrame = null;
	return frames;
}

@Override
public HandshakeBuilder postProcessHandshakeResponseAsServer( Handshakedata request , HandshakeBuilder response) throws InvalidHandshakeException {
	String seckey = request.getFieldValue ( "Sec-WebSocket-Key" );
	if ( seckey == null )
		throw new InvalidHandshakeException ( "missing Sec-WebSocket-Key" );
	response.put( "Sec-WebSocket-Accept" , generateFinalKey( seckey ) );
	return super.postProcessHandshakeResponseAsServer ( request , response );
}

protected void initialiseParse(String input, String baseUri, ParseErrorList errors) {
    Validate.notNull(input, "String input must not be null");
    Validate.notNull(baseUri, "BaseURI must not be null");

    doc = new Document(baseUri);
    reader = new CharacterReader(input);
    this.errors = errors;
    tokeniser = new Tokeniser(reader, errors);
    stack = new ArrayList<Element>(32);
    this.baseUri = baseUri;
}

public /*static*/ ByteBuffer createHandshake( Handshakedata handshakedata , Role ownrole ){
	StringBuilder bui = new StringBuilder ( 100 );
	if( ownrole == Role.CLIENT){
		bui.append ( "GET " );
		bui.append ( handshakedata.getResourceDescriptor () );
		bui.append ( " HTTP/1.1" );
	}
	else if( ownrole == Role.SERVER ){
		bui.append ( "HTTP/1.1 101 "+handshakedata.getHttpStatusMessage() );
	}
	else{
		throw new RuntimeException ( "unknow role" );
	}
	bui.append ( "\r\n" );
	Iterator<String> it = handshakedata.iterateHttpFields ();
	while( it.hasNext () ){
		String fieldname = it.next ();
		String fieldvalue = handshakedata.getFieldValue ( fieldname );
		bui.append ( fieldname );
		bui.append ( ": ");
		bui.append ( fieldvalue );
		bui.append ( "\r\n" );
	}
	bui.append ( "\r\n" );
	byte[] httpheader = bui.toString ().getBytes ( UTF8_CHARSET );
	byte[] content = handshakedata.getContent ();
	ByteBuffer bytebuffer = ByteBuffer.allocate ( ( content==null ? 0 : content.length ) + httpheader.length );
	bytebuffer.put ( httpheader );
	if( content!=null )
		bytebuffer.put ( content );
	return bytebuffer;

}

/**
 * Get the {@link FormElement} forms from the selected elements, if any.
 * @return a list of {@link FormElement}s pulled from the matched elements. The list will be empty if the elements contain
 * no forms.
 */
public List<FormElement> forms() {
    ArrayList<FormElement> forms = new ArrayList<>();
    for (Element el: this)
        if (el instanceof FormElement)
            forms.add((FormElement) el);
    return forms;
}

public String header(String name) {
    Validate.notNull(name, "Header name must not be null");
    return getHeaderCaseInsensitive(name);
}

Document parse(String input, String baseUri, ParseErrorList errors) {
    initialiseParse(input, baseUri, errors);
    runParser();
    return doc;
}

static Document parseInputStream(CharsetDoc charsetDoc, String baseUri, Parser parser) throws IOException {
    // if doc != null it was fully parsed during charset detection; so just return that
    if (charsetDoc.doc != null)
        return charsetDoc.doc;

    final InputStream input = charsetDoc.input;
    Validate.notNull(input);
    final Document doc;
    final Charset charset = charsetDoc.charset;
    try (BufferedReader reader = new BufferedReader(new InputStreamReader(input, charset), DefaultBufferSize)) {
        maybeSkipBom(reader, charsetDoc);
        try {
            doc = parser.parseInput(reader, baseUri);
        } catch (UncheckedIOException e) {
            // io exception when parsing (not seen before because reading the stream as we go)
            throw e.getCause();
        }
        doc.outputSettings().charset(charset);
        if (!charset.canEncode()) {
            // some charsets can read but not encode; switch to an encodable charset and update the meta el
            doc.charset(UTF_8);
        }
    }
    return doc;
}
